"use client";

import React, {
  useEffect,
  useMemo,
  useRef,
  useState,
  useLayoutEffect,
  useCallback,
} from "react";
import {
  ComposedChart,
  CartesianGrid,
  Line,
  XAxis,
  YAxis,
  ReferenceLine,
  Tooltip,
  ResponsiveContainer,
  Area,
  ScatterChart,
  Scatter,
  BarChart,
  Bar,
  Cell,
  Legend,
  Customized,
} from "recharts";
import * as THREE from "three";
import { OrbitControls } from "three/examples/jsm/controls/OrbitControls.js";

const tradeNum = (value) => {
  if (typeof value === "number") return Number.isFinite(value) ? value : null;
  if (typeof value === "string") {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : null;
  }
  if (value == null) return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const pickTradeNum = (...values) => {
  for (const value of values) {
    const parsed = tradeNum(value);
    if (parsed != null) return parsed;
  }
  return null;
};

const inferTradeDirection = (trade) => {
  const raw =
    (trade as any)?.dir ??
    (trade as any)?.direction ??
    (trade as any)?.sideNum ??
    (trade as any)?.side ??
    (trade as any)?.sideText;
  const asNumber = tradeNum(raw);
  if (asNumber === -1) return -1;
  if (asNumber === 1) return 1;
  const text = typeof raw === "string" ? raw.trim().toLowerCase() : "";
  if (
    text === "sell" ||
    text === "short" ||
    text.startsWith("sell") ||
    text.startsWith("short") ||
    text === "s"
  ) {
    return -1;
  }
  return 1;
};

const isTpExitReason = (value) => {
  const reason = typeof value === "string" ? value.trim().toLowerCase() : "";
  return (
    reason === "tp" ||
    reason === "take profit" ||
    reason === "takeprofit" ||
    reason.includes("take profit")
  );
};

const isStopExitReason = (value) => {
  const reason = typeof value === "string" ? value.trim().toLowerCase() : "";
  return (
    reason === "sl" ||
    reason === "be" ||
    reason === "trailing" ||
    reason === "stop loss" ||
    reason === "stoploss" ||
    reason.includes("stop loss") ||
    reason.includes("break even") ||
    reason.includes("breakeven") ||
    reason.includes("trailing")
  );
};

const resolveTradePnlSnapshot = (trade, dollarsPerMove, candles, tpDist, slDist) => {
  const safeTrade = trade ?? {};
  const dir = inferTradeDirection(safeTrade);
  const candleList = Array.isArray(candles) ? candles : [];
  const clampIndex = (rawIndex) => {
    if (!candleList.length) return null;
    const index = tradeNum(rawIndex);
    if (index == null) return null;
    return Math.max(0, Math.min(candleList.length - 1, Math.round(index)));
  };

  const entryIndex = clampIndex(
    (safeTrade as any).entryIndex ??
      (safeTrade as any).signalIndex ??
      (safeTrade as any).openIndex
  );
  const exitIndex = clampIndex(
    (safeTrade as any).exitIndex ??
      (safeTrade as any).closeIndex ??
      (safeTrade as any).endIndex
  );
  const entryCandle = entryIndex != null ? candleList[entryIndex] : null;
  const exitCandle = exitIndex != null ? candleList[exitIndex] : null;
  const lastCandle = candleList.length ? candleList[candleList.length - 1] : null;

  const entryPrice = pickTradeNum(
    (safeTrade as any).entryPrice,
    (safeTrade as any).openPrice,
    (safeTrade as any).entry,
    (safeTrade as any).open,
    (safeTrade as any).priceEntry,
    (safeTrade as any).entryPx,
    entryCandle?.open,
    entryCandle?.close
  );

  let takeProfitPrice = pickTradeNum(
    (safeTrade as any).tpPrice,
    (safeTrade as any).tp,
    (safeTrade as any).takeProfitPrice,
    (safeTrade as any).takeProfit,
    entryPrice != null && tradeNum(tpDist) != null
      ? entryPrice + dir * Math.abs(tradeNum(tpDist))
      : null
  );
  let stopLossPrice = pickTradeNum(
    (safeTrade as any).slPrice,
    (safeTrade as any).sl,
    (safeTrade as any).stopLossPrice,
    (safeTrade as any).stopLoss,
    entryPrice != null && tradeNum(slDist) != null
      ? entryPrice - dir * Math.abs(tradeNum(slDist))
      : null
  );

  const exitReason =
    (safeTrade as any).exitReason ??
    (safeTrade as any).exit_reason ??
    (safeTrade as any).reasonExit ??
    (safeTrade as any).exitTag ??
    (safeTrade as any).exit_source ??
    (safeTrade as any).exitSource;

  const livePrice = (safeTrade as any).isOpen
    ? pickTradeNum(
        (safeTrade as any).markPrice,
        (safeTrade as any).currentPrice,
        (safeTrade as any).lastPrice,
        (safeTrade as any).priceNow,
        (safeTrade as any).nowPrice,
        lastCandle?.close,
        lastCandle?.open
      )
    : null;

  const explicitExitPrice = pickTradeNum(
    (safeTrade as any).exitPrice,
    (safeTrade as any).closePrice,
    (safeTrade as any).exit,
    (safeTrade as any).close,
    (safeTrade as any).priceExit,
    (safeTrade as any).exitPx,
    exitCandle?.close,
    exitCandle?.open,
    livePrice
  );
  const exitPrice = (safeTrade as any).isOpen
    ? explicitExitPrice
    : isTpExitReason(exitReason) && takeProfitPrice != null
      ? takeProfitPrice
      : isStopExitReason(exitReason) && stopLossPrice != null
        ? stopLossPrice
        : explicitExitPrice;

  // Keep TP/SL visuals aligned with the exact executed exit pricing path.
  if (!(safeTrade as any).isOpen && exitPrice != null) {
    if (isTpExitReason(exitReason)) takeProfitPrice = exitPrice;
    if (isStopExitReason(exitReason)) stopLossPrice = exitPrice;
  }

  const storedPnl = pickTradeNum(
    (safeTrade as any).isOpen ? (safeTrade as any).unrealizedPnl : null,
    (safeTrade as any).pnl,
    (safeTrade as any).realizedPnl,
    (safeTrade as any).profit,
    (safeTrade as any).netPnl,
    (safeTrade as any).pnlUsd
  );

  const dpm = Math.max(1e-6, Math.abs(tradeNum(dollarsPerMove) ?? 1));
  const pricePnl =
    entryPrice != null && exitPrice != null
      ? (exitPrice - entryPrice) * dir * dpm
      : null;

  return {
    dir,
    entryIndex,
    exitIndex,
    entryPrice,
    exitPrice,
    tpPrice: takeProfitPrice,
    slPrice: stopLossPrice,
    exitReason,
    storedPnl,
    pricePnl,
    effectivePnl: pricePnl != null ? pricePnl : storedPnl,
  };
};

const normalizeTradePnlValues = (trade, dollarsPerMove, candles, tpDist, slDist) => {
  if (!trade || typeof trade !== "object") return trade;

  const snapshot = resolveTradePnlSnapshot(
    trade,
    dollarsPerMove,
    candles,
    tpDist,
    slDist
  );
  const next = { ...(trade as any) };

  if (snapshot.entryPrice != null) next.entryPrice = snapshot.entryPrice;
  if (snapshot.tpPrice != null) next.tpPrice = snapshot.tpPrice;
  if (snapshot.slPrice != null) next.slPrice = snapshot.slPrice;
  if (snapshot.exitPrice != null) {
    if (next.isOpen) {
      next.markPrice =
        typeof next.markPrice === "number" && Number.isFinite(next.markPrice)
          ? next.markPrice
          : snapshot.exitPrice;
    } else {
      next.exitPrice = snapshot.exitPrice;
    }
  }

  next.direction = snapshot.dir;
  next.dir = snapshot.dir;

  if (snapshot.effectivePnl != null) {
    const rounded = Number(snapshot.effectivePnl.toFixed(2));
    if (next.isOpen) {
      next.unrealizedPnl = rounded;
    } else {
      next.pnl = rounded;
      next.realizedPnl = rounded;
      next.netPnl = rounded;
      next.pnlUsd = rounded;
      next.win = rounded >= 0;
      next.label = rounded >= 0 ? 1 : -1;
    }
  }

  return next;
};

const normalizeTradeCollectionPnl = (trades, dollarsPerMove, candles, tpDist, slDist) => {
  if (!Array.isArray(trades) || trades.length === 0) return [];
  return trades.map((trade) =>
    normalizeTradePnlValues(trade, dollarsPerMove, candles, tpDist, slDist)
  );
};

// --- Trade Details Modal (module-scope) ---
function TradeDetailsModalImpl({
  trade,
  candles,
  dollarsPerMove,
  interval,
  parseMode,
  tpDist,
  slDist,
  onClose,
}) {
  const num = (v) => {
    if (typeof v === "number") return v;
    if (typeof v === "string") {
      const x = Number(v);
      return Number.isFinite(x) ? x : NaN;
    }
    if (v == null) return NaN;
    const x = Number(v);
    return Number.isFinite(x) ? x : NaN;
  };

  const pnlSnapshot = resolveTradePnlSnapshot(
    trade,
    dollarsPerMove,
    candles,
    tpDist,
    slDist
  );
  const entryPrice = pnlSnapshot.entryPrice ?? num((trade as any).entryPrice);
  const exitPrice = pnlSnapshot.exitPrice;
  const dir = pnlSnapshot.dir;
  const pnl = pnlSnapshot.effectivePnl;

  const isWin = Number.isFinite(pnl) ? pnl >= 0 : false;
  const accent = isWin ? "rgba(52,211,153,0.95)" : "rgba(248,113,113,0.95)";

  const tpPrice = pnlSnapshot.tpPrice;
  const slPrice = pnlSnapshot.slPrice;

  const durationMin = useMemo(() => {
    const nowT = (trade as any).isOpen ? Date.now() : null;
    const endT = (trade as any).isOpen ? nowT : (trade as any).exitTime;
    return minutesBetween((trade as any).entryTime, endT, parseMode) ?? null;
  }, [trade, parseMode]);

  const pathStats = useMemo(() => {
    const a = Number((trade as any).entryIndex ?? -1);
    const b = Number((trade as any).exitIndex ?? -1);
    if (!candles?.length || a < 0) return null;

    const start = clampInt(a, 0, candles.length - 1);
    const end = b >= 0 ? clampInt(b, 0, candles.length - 1) : start;

    const ep = entryPrice;
    if (!Number.isFinite(ep)) return null;
    const pnlPerMove = Number.isFinite(Number(dollarsPerMove))
      ? Number(dollarsPerMove)
      : 1;

    let maxFav = 0;
    let maxAdv = 0;
    let peak = -Infinity;
    let trough = Infinity;

    for (let i = start; i <= end; i++) {
      const c: any = candles[i];
      const hi = num(c?.high);
      const lo = num(c?.low);
      const close = num(c?.close);

      const hiPx = Number.isFinite(hi) ? hi : close;
      const loPx = Number.isFinite(lo) ? lo : close;
      if (!Number.isFinite(hiPx) || !Number.isFinite(loPx)) continue;

      const favorablePx = dir === 1 ? hiPx : loPx;
      const adversePx = dir === 1 ? loPx : hiPx;
      const favorablePnl = Math.max(
        0,
        (favorablePx - ep) * dir * pnlPerMove
      );
      const adversePnl = Math.max(
        0,
        -((adversePx - ep) * dir * pnlPerMove)
      );

      if (favorablePnl > maxFav) maxFav = favorablePnl;
      if (adversePnl > maxAdv) maxAdv = adversePnl;

      if (hiPx > peak) peak = hiPx;
      if (loPx < trough) trough = loPx;
    }

    // By definition, favorable/adverse excursion cannot exceed configured TP/SL caps.
    const tpCap = Number.isFinite(tpPrice)
      ? Math.max(0, Math.abs((tpPrice as number) - ep) * pnlPerMove)
      : null;
    const slCap = Number.isFinite(slPrice)
      ? Math.max(0, Math.abs((slPrice as number) - ep) * pnlPerMove)
      : null;

    if (tpCap != null) maxFav = Math.min(maxFav, tpCap);
    if (slCap != null) maxAdv = Math.min(maxAdv, slCap);

    return {
      entryIndex: start,
      exitIndex: end,
      maxFavorable: Number.isFinite(maxFav) ? maxFav : null,
      maxAdverse: Number.isFinite(maxAdv) ? maxAdv : null,
      peak,
      trough,
    };
  }, [trade, candles, dollarsPerMove, entryPrice, dir, tpPrice, slPrice]);

  useEffect(() => {
    const prev = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    const onKey = (e) => {
      if (e.key === "Escape") onClose?.();
    };
    window.addEventListener("keydown", onKey);
    return () => {
      document.body.style.overflow = prev;
      window.removeEventListener("keydown", onKey);
    };
  }, [onClose]);

  const fmt = (v, d = 3) =>
    Number.isFinite(v)
      ? Number(v).toLocaleString(undefined, { maximumFractionDigits: d })
      : "—";

  const fmtPrice = (v) =>
    Number.isFinite(v)
      ? Number(v).toLocaleString(undefined, {
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        })
      : "—";
  const fmtUsd = (v) =>
    Number.isFinite(v)
      ? `${v >= 0 ? "+" : "-"}$${Math.abs(v).toLocaleString(undefined, {
          maximumFractionDigits: 2,
        })}`
      : "—";

  const fmtPct = (v, d = 1) =>
    Number.isFinite(v) ? `${(Number(v) * 100).toFixed(d)}%` : "—";
  const titleId = displayIdForNode(trade as any);

  const InfoBox = ({ label, value, tone = "neutral" }) => {
    const isEmpty =
      value == null ||
      value === "" ||
      value === "—" ||
      (typeof value === "number" && !Number.isFinite(value));

    const toneMap: Record<
      string,
      { border: string; bg: string; value: string; label: string }
    > = {
      neutral: {
        border: "rgba(255,255,255,0.10)",
        bg: "rgba(255,255,255,0.03)",
        value: "rgba(255,255,255,0.88)",
        label: "rgba(255,255,255,0.72)",
      },
      green: {
        border: "rgba(52,211,153,0.22)",
        bg: "linear-gradient(180deg, rgba(52,211,153,0.10), rgba(255,255,255,0.02))",
        value: "rgba(167,243,208,0.98)",
        label: "rgba(167,243,208,0.72)",
      },
      red: {
        border: "rgba(248,113,113,0.22)",
        bg: "linear-gradient(180deg, rgba(248,113,113,0.10), rgba(255,255,255,0.02))",
        value: "rgba(254,202,202,0.98)",
        label: "rgba(254,202,202,0.72)",
      },
      blue: {
        border: "rgba(96,165,250,0.22)",
        bg: "linear-gradient(180deg, rgba(96,165,250,0.10), rgba(255,255,255,0.02))",
        value: "rgba(191,219,254,0.98)",
        label: "rgba(191,219,254,0.72)",
      },
      amber: {
        border: "rgba(251,191,36,0.22)",
        bg: "linear-gradient(180deg, rgba(251,191,36,0.10), rgba(255,255,255,0.02))",
        value: "rgba(253,230,138,0.98)",
        label: "rgba(253,230,138,0.72)",
      },
    };

    const t = toneMap[tone] ?? toneMap.neutral;

    return (
      <div
        style={{
          border: `1px solid ${t.border}`,
          background: t.bg,
          borderRadius: 14,
          padding: "10px 12px",
          minHeight: 58,
          display: "flex",
          flexDirection: "column",
          justifyContent: "space-between",
          boxShadow: "0 10px 30px rgba(0,0,0,0.35) inset",
        }}
      >
        <div
          style={{
            fontSize: 9,
            letterSpacing: 0.7,
            opacity: 1,
            color: t.label,
            textTransform: "uppercase",
            marginBottom: 6,
            lineHeight: 1.1,
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
          }}
        >
          {label}
        </div>
        <div
          style={{
            fontSize: 12,
            fontWeight: 850,
            color: isEmpty ? "rgba(255,255,255,0.55)" : t.value,
            lineHeight: 1.15,
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
          }}
          title={typeof value === "string" ? value : undefined}
        >
          {isEmpty ? "N/A" : value}
        </div>
      </div>
    );
  };

  return (
    <div
      onMouseDown={(e) => {
        // click backdrop to close
        if (e.target === e.currentTarget) onClose?.();
      }}
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 9999,
        background: "rgba(0,0,0,0.6)",
        backdropFilter: "blur(6px)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 18,
      }}
    >
      <div
        style={{
          width: "min(1120px, 96vw)",
          height: "min(900px, 90vh)",
          borderRadius: 18,
          border: "1px solid rgba(255,255,255,0.10)",
          background: "rgba(12,12,12,0.96)",
          boxShadow: "0 28px 120px rgba(0,0,0,0.65)",
          overflow: "hidden",
          display: "flex",
          flexDirection: "column",
        }}
      >
        {/* Header */}
        <div
          style={{
            padding: "14px 16px",
            borderBottom: "1px solid rgba(255,255,255,0.08)",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            gap: 12,
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "baseline",
              gap: 10,
              flexWrap: "wrap",
            }}
          >
            <div
              style={{
                fontSize: 16,
                fontWeight: 900,
                color: "rgba(255,255,255,0.92)",
              }}
            >
              {titleId || "Trade"}
            </div>
            <div
              style={{
                fontSize: 12,
                fontWeight: 900,
                padding: "3px 10px",
                borderRadius: 999,
                background: "rgba(255,255,255,0.06)",
                border: `1px solid ${accent}`,
                color: accent,
              }}
            >
              {(trade as any).isOpen ? "OPEN" : isWin ? "WIN" : "LOSS"}
            </div>
            {(trade as any).entryModel ?? (trade as any).model ? (
              <div
                style={{
                  fontSize: 12,
                  opacity: 0.85,
                  color: "rgba(255,255,255,0.72)",
                }}
              >
                <span
                  style={{ fontWeight: 800, color: "rgba(255,255,255,0.82)" }}
                >
                  {canonicalModelName(
                    (trade as any).entryModel ?? (trade as any).model
                  )}
                </span>
              </div>
            ) : null}
          </div>

          <button
            onClick={onClose}
            style={{
              height: 34,
              padding: "0 12px",
              borderRadius: 10,
              border: "1px solid rgba(255,255,255,0.14)",
              background: "rgba(255,255,255,0.06)",
              color: "rgba(255,255,255,0.86)",
              fontSize: 12,
              fontWeight: 800,
              cursor: "pointer",
            }}
          >
            Close
          </button>
        </div>

        {/* AI Cluster Info */}
        <div style={{ padding: "12px 16px" }}>
          <div
            style={{
              display: "flex",
              alignItems: "baseline",
              justifyContent: "space-between",
              gap: 12,
              marginBottom: 10,
            }}
          >
            <div
              style={{
                fontSize: 12,
                fontWeight: 900,
                letterSpacing: 0.4,
                opacity: 0.92,
              }}
            >
              AI Cluster Info
            </div>
            <div
              style={{
                fontSize: 11,
                opacity: 0.72,
                textAlign: "right",
                lineHeight: 1.2,
              }}
            >
              <span style={{ opacity: 0.9 }}>
                AI Margin{" "}
                <b style={{ color: "rgba(255,255,255,0.88)" }}>
                  {fmtPct(num((trade as any).aiMargin), 1)}
                </b>
              </span>
              <span style={{ opacity: 0.45 }}> · </span>
              <span style={{ opacity: 0.9 }}>
                Cluster{" "}
                <b style={{ color: "rgba(255,255,255,0.88)" }}>
                  {(trade as any).closestCluster ??
                    (trade as any).clusterName ??
                    (trade as any).clusterLabel ??
                    "—"}
                </b>
              </span>
              <span style={{ opacity: 0.45 }}> · </span>
              <span style={{ opacity: 0.9 }}>
                Group{" "}
                <b style={{ color: "rgba(255,255,255,0.82)" }}>
                  {(trade as any).hdbClusterId ??
                    (trade as any).clusterGroupId ??
                    (trade as any).clusterGroup ??
                    "—"}
                </b>
              </span>
            </div>
          </div>

          {/* Row 1 */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(4, minmax(0, 1fr))",
              gap: 10,
              marginBottom: 10,
            }}
          >
            <InfoBox
              label="Entry Reason"
              tone="blue"
              value={
                (trade as any).entryReason ??
                (trade as any).entry_reason ??
                (trade as any).reasonEntry ??
                (trade as any).entryTag ??
                (trade as any).entry_source ??
                (trade as any).entrySource ??
                ((trade as any).entryModel
                  ? `Model: ${canonicalModelName((trade as any).entryModel)}`
                  : null) ??
                (trade as any).chunkType ??
                (trade as any).setup ??
                (trade as any).strategy ??
                "—"
              }
            />
            <InfoBox label="Entry Price" value={fmtPrice(entryPrice)} />
            <InfoBox
              label="Exit Reason"
              tone="blue"
              value={
                (trade as any).exitReason ??
                (trade as any).exit_reason ??
                (trade as any).reasonExit ??
                (trade as any).exitTag ??
                (trade as any).exit_source ??
                (trade as any).exitSource ??
                ((trade as any).exitModel
                  ? `Model: ${canonicalModelName((trade as any).exitModel)}`
                  : null) ??
                "—"
              }
            />
            <InfoBox
              label="Exit Price"
              value={Number.isFinite(exitPrice) ? fmtPrice(exitPrice) : "—"}
            />
          </div>

          {/* Row 2 */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(2, minmax(0, 1fr))",
              gap: 10,
              marginBottom: 10,
            }}
          >
            <InfoBox
              label="PnL"
              value={fmtUsd(pnl)}
              tone={Number.isFinite(pnl) ? (pnl >= 0 ? "green" : "red") : "neutral"}
            />
            <InfoBox
              label="Duration"
              value={
                durationMin != null ? formatMinutesShort(durationMin) : "—"
              }
            />
          </div>

          {/* Row 3 */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(4, minmax(0, 1fr))",
              gap: 10,
              marginBottom: 10,
            }}
          >
            <InfoBox
              label="Take Profit"
              value={Number.isFinite(tpPrice) ? fmtPrice(tpPrice) : "—"}
              tone="green"
            />
            <InfoBox
              label="Stop Loss"
              value={Number.isFinite(slPrice) ? fmtPrice(slPrice) : "—"}
              tone="red"
            />
            <InfoBox
              label="Peak (MFE)"
              value={
                pathStats?.maxFavorable != null
                  ? fmtUsd(pathStats.maxFavorable)
                  : "—"
              }
              tone="green"
            />
            <InfoBox
              label="DD (MAE)"
              value={
                pathStats?.maxAdverse != null
                  ? fmtUsd(pathStats.maxAdverse)
                  : "—"
              }
              tone="red"
            />
          </div>

          {/* Row 4 */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(3, minmax(0, 1fr))",
              gap: 10,
            }}
          >
            <InfoBox
              label="Session"
              value={(trade as any).session ?? (trade as any).sess ?? "—"}
            />
            <InfoBox
              label="Model"
              tone="amber"
              value={(() => {
                const m =
                  (trade as any).entryModel ??
                  (trade as any).model ??
                  (trade as any).modelName ??
                  (trade as any).exitModel ??
                  (trade as any).chunkType ??
                  (trade as any).strategy ??
                  (trade as any).setup;
                return m ? canonicalModelName(m) : "—";
              })()}
            />
            <InfoBox
              label="Most Influential Dimension"
              tone="blue"
              value={
                (trade as any).mostInfluentialDimension ??
                (trade as any).most_influential_dimension ??
                (trade as any).mostInfluentialDim ??
                (trade as any).influentialDimension ??
                (trade as any).influential_dimension ??
                (trade as any).topDim ??
                (trade as any).top_dimension ??
                (trade as any).bestDim ??
                (trade as any).dimension ??
                (trade as any).dim ??
                "—"
              }
            />
          </div>
        </div>

        <TradeCandlestickChart
          trade={trade}
          candles={candles}
          interval={interval}
          parseMode={parseMode}
          tpDist={tpDist}
          slDist={slDist}
          heightPx={420}
        />
      </div>
    </div>
  );
}
// --- End Trade Details Modal ---

export const AIZipTradeDetailsModal = TradeDetailsModalImpl;

// --- Trade Candlestick Chart (SVG, pro interactions) ---
function TradeCandlestickChartSVG({
  trade,
  candles,
  interval,
  parseMode,
  tpDist,
  slDist,
  heightPx = 420,
}: {
  trade: any;
  candles: any[];
  interval?: string;
  parseMode?: "utc" | "local" | string;
  tpDist?: number;
  slDist?: number;
  heightPx?: number;
}) {
  const wrapRef = React.useRef<HTMLDivElement | null>(null);

  // Helpers
  const num = (v: any) => {
    const n =
      typeof v === "number" ? v : v != null && v !== "" ? Number(v) : NaN;
    return Number.isFinite(n) ? n : null;
  };
  const fmt2 = (v: any) => {
    const n = num(v);
    return n == null ? "—" : n.toFixed(2);
  };

  const baseData = Array.isArray(candles) ? candles : [];
  const N = baseData.length;

  const priceSnapshot = React.useMemo(
    () => resolveTradePnlSnapshot(trade, 1, baseData, tpDist, slDist),
    [trade, baseData, tpDist, slDist]
  );
  const isLong = priceSnapshot.dir !== -1;
  const entrySide = isLong ? "Buy" : "Sell";
  const exitSide = isLong ? "Sell" : "Buy";

  // Index resolution
  const resolveIdx = (obj: any, keys: string[]) => {
    for (const k of keys) {
      const v = num(obj?.[k]);
      if (v != null) return Math.max(0, Math.min(N - 1, Math.round(v)));
    }
    return null;
  };

  const entryIdxDirect =
    resolveIdx(trade, [
      "entryIndex",
      "entryIdx",
      "entryBarIndex",
      "entryBar",
      "entryCandleIndex",
      "entry_i",
    ]) ?? null;
  const exitIdxDirect =
    resolveIdx(trade, [
      "exitIndex",
      "exitIdx",
      "exitBarIndex",
      "exitBar",
      "exitCandleIndex",
      "exit_i",
    ]) ?? null;

  // Time-based fallback
  const parseTime = (t: any) => {
    if (t == null) return null;
    if (typeof t === "number") return t;
    const s = String(t);
    const d = new Date(s);
    const ms = d.getTime();
    return Number.isFinite(ms) ? ms : null;
  };
  const entryT = parseTime(
    (trade as any)?.entryTime ??
      (trade as any)?.entryTs ??
      (trade as any)?.openTime
  );
  const exitT = parseTime(
    (trade as any)?.exitTime ??
      (trade as any)?.exitTs ??
      (trade as any)?.closeTime
  );

  const candleTimeMs = (c: any) =>
    parseTime(
      c?.t ?? c?.time ?? c?.timestamp ?? c?.ts ?? c?.date ?? c?.datetime
    );

  const findNearestIdxByTime = (target: number | null) => {
    if (target == null || N === 0) return null;
    let bestI = 0;
    let bestD = Infinity;
    for (let i = 0; i < N; i++) {
      const tm = candleTimeMs(baseData[i]);
      if (tm == null) continue;
      const d = Math.abs(tm - target);
      if (d < bestD) {
        bestD = d;
        bestI = i;
      }
    }
    return Number.isFinite(bestD) ? bestI : null;
  };

  const entryIdx = entryIdxDirect ?? findNearestIdxByTime(entryT) ?? 0;
  const exitIdx =
    exitIdxDirect ?? (exitT != null ? findNearestIdxByTime(exitT) : null);

  // Prices
  const entryPrice =
    priceSnapshot.entryPrice ??
    num(
      (trade as any)?.entryPrice ??
        (trade as any)?.entry ??
        (trade as any)?.openPrice
    ) ??
    (entryIdx != null
      ? num(
          baseData[entryIdx]?.o ??
            baseData[entryIdx]?.open ??
            baseData[entryIdx]?.c ??
            baseData[entryIdx]?.close
        )
      : null);
  const exitPrice =
    priceSnapshot.exitPrice ??
    num(
      (trade as any)?.exitPrice ??
        (trade as any)?.exit ??
        (trade as any)?.closePrice
    ) ??
    // fallback: if exit candle exists, use its close
    (exitIdx != null
      ? num(baseData[exitIdx]?.c ?? baseData[exitIdx]?.close)
      : null);

  const tp = priceSnapshot.tpPrice;
  const sl = priceSnapshot.slPrice;

  // Initial window: tradeLen*3, but allow zoom out to full history
  const tradeLenRaw =
    num(
      (trade as any)?.bars ??
        (trade as any)?.barsHeld ??
        (trade as any)?.barCount ??
        (trade as any)?.lenBars
    ) ?? (exitIdx != null ? Math.max(1, exitIdx - entryIdx + 1) : 30);
  const initialWin = Math.max(30, Math.ceil(tradeLenRaw * 3));

  const initialStart = Math.max(0, entryIdx - Math.floor(initialWin * 0.35));
  const initialEnd = Math.min(N - 1, initialStart + initialWin - 1);

  const [viewStart, setViewStart] = React.useState<number>(initialStart);
  const [viewEnd, setViewEnd] = React.useState<number>(
    Math.max(initialStart, initialEnd)
  );

  // Hover / interaction state
  const [hoverI, setHoverI] = React.useState<number | null>(null);
  const [mouseXY, setMouseXY] = React.useState<{ x: number; y: number } | null>(
    null
  );
  const dragRef = React.useRef<{
    dragging: boolean;
    startX: number;
    startStart: number;
    startEnd: number;
  }>({ dragging: false, startX: 0, startStart: 0, startEnd: 0 });

  // Dimensions
  const pad = 16;
  const W = 1040; // viewBox width
  const H = Math.max(320, Math.min(560, heightPx));
  const plot = { x: pad, y: pad, w: W - pad * 2, h: H - pad * 2 - 30 }; // reserve bottom for x-axis labels

  const viewData = React.useMemo(() => {
    const a = Math.max(0, Math.min(N - 1, viewStart));
    const b = Math.max(0, Math.min(N - 1, viewEnd));
    const s = Math.min(a, b);
    const e = Math.max(a, b);
    return baseData.slice(s, e + 1).map((c, i) => ({ c, i: s + i }));
  }, [baseData, N, viewStart, viewEnd]);

  // OHLC extraction
  const ohlc = (c: any) => {
    const o = num(c?.o ?? c?.open);
    const h = num(c?.h ?? c?.high);
    const l = num(c?.l ?? c?.low);
    const cl = num(c?.c ?? c?.close);
    return { o, h, l, c: cl };
  };

  const yDomain = React.useMemo(() => {
    let lo = Infinity;
    let hi = -Infinity;
    for (const { c } of viewData) {
      const { h, l } = ohlc(c);
      if (h != null) hi = Math.max(hi, h);
      if (l != null) lo = Math.min(lo, l);
    }
    // include important levels
    for (const v of [entryPrice, exitPrice, tp, sl]) {
      if (v != null) {
        hi = Math.max(hi, v);
        lo = Math.min(lo, v);
      }
    }
    if (!Number.isFinite(lo) || !Number.isFinite(hi) || lo === hi) {
      lo = (entryPrice ?? 0) - 1;
      hi = (entryPrice ?? 0) + 1;
    }
    const range = hi - lo;
    const padY = Math.max(range * 0.18, 0.5); // bigger padding than before
    return { lo: lo - padY, hi: hi + padY };
  }, [viewData, entryPrice, exitPrice, tp, sl]);

  const xForIndex = (idx: number) => {
    const s = viewData.length <= 1 ? 0 : viewData[0].i;
    const e = viewData.length <= 1 ? 1 : viewData[viewData.length - 1].i;
    const t = e === s ? 0 : (idx - s) / (e - s);
    return plot.x + t * plot.w;
  };

  const yForPrice = (p: number) => {
    const { lo, hi } = yDomain;
    const t = (p - lo) / (hi - lo);
    return plot.y + (1 - t) * plot.h;
  };

  // Map mouse to index
  const idxFromMouseX = (mx: number) => {
    const s = viewData.length <= 1 ? 0 : viewData[0].i;
    const e = viewData.length <= 1 ? 1 : viewData[viewData.length - 1].i;
    const t = Math.max(0, Math.min(1, (mx - plot.x) / plot.w));
    return Math.round(s + t * (e - s));
  };

  const onMouseMove = (e: React.MouseEvent) => {
    const r = (e.currentTarget as any).getBoundingClientRect();
    const x = ((e.clientX - r.left) / r.width) * W;
    const y = ((e.clientY - r.top) / r.height) * H;
    setMouseXY({ x, y });

    if (dragRef.current.dragging) {
      const dx = x - dragRef.current.startX;
      const barsPerPx = (viewEnd - viewStart + 1) / plot.w;
      const shift = Math.round(-dx * barsPerPx);
      const win = dragRef.current.startEnd - dragRef.current.startStart;
      let ns = dragRef.current.startStart + shift;
      let ne = dragRef.current.startEnd + shift;
      if (ns < 0) {
        ne -= ns;
        ns = 0;
      }
      if (ne > N - 1) {
        const over = ne - (N - 1);
        ns -= over;
        ne = N - 1;
        if (ns < 0) ns = 0;
      }
      // keep window size
      if (ne - ns !== win) ne = Math.min(N - 1, ns + win);
      setViewStart(ns);
      setViewEnd(ne);
      return;
    }

    const i = idxFromMouseX(x);
    setHoverI(i);
  };

  const onMouseLeave = () => {
    setMouseXY(null);
    setHoverI(null);
    dragRef.current.dragging = false;
  };

  const onMouseDown = (e: React.MouseEvent) => {
    const r = (e.currentTarget as any).getBoundingClientRect();
    const x = ((e.clientX - r.left) / r.width) * W;
    dragRef.current = {
      dragging: true,
      startX: x,
      startStart: viewStart,
      startEnd: viewEnd,
    };
  };

  const onMouseUp = () => {
    dragRef.current.dragging = false;
  };

  const onWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    if (N < 5) return;
    const r = (e.currentTarget as any).getBoundingClientRect();
    const x = ((e.clientX - r.left) / r.width) * W;

    const centerIdx = idxFromMouseX(x);
    const curWin = Math.max(5, viewEnd - viewStart + 1);
    const zoomIn = e.deltaY < 0;
    const factor = zoomIn ? 0.85 : 1.18;
    let newWin = Math.round(curWin * factor);
    newWin = Math.max(10, Math.min(N, newWin));

    let ns =
      centerIdx - Math.round(newWin * ((centerIdx - viewStart) / curWin));
    let ne = ns + newWin - 1;

    if (ns < 0) {
      ne -= ns;
      ns = 0;
    }
    if (ne > N - 1) {
      const over = ne - (N - 1);
      ns -= over;
      ne = N - 1;
      if (ns < 0) ns = 0;
    }
    setViewStart(ns);
    setViewEnd(ne);
  };

  const onDoubleClick = () => {
    // reset back to initial window around entry
    setViewStart(initialStart);
    setViewEnd(Math.max(initialStart, initialEnd));
  };

  const candleWidth = React.useMemo(() => {
    const n = Math.max(1, viewData.length);
    const px = plot.w / n;
    return Math.max(2, Math.min(18, px * 0.7));
  }, [viewData.length, plot.w]);

  // Entry/Exit marker placement near the candle (above/below the candle)
  const clamp = (v: number, lo: number, hi: number) =>
    Math.max(lo, Math.min(hi, v));

  const arrow = (
    x: number,
    tipY: number,
    dir: "up" | "down",
    color: string
  ) => {
    // tipY is the arrow tip (points into the candle)
    const head = 5;
    const stem = 7;
    const headPath =
      dir === "up"
        ? `M ${x} ${tipY} L ${x - head} ${tipY + head} L ${x + head} ${
            tipY + head
          } Z`
        : `M ${x} ${tipY} L ${x - head} ${tipY - head} L ${x + head} ${
            tipY - head
          } Z`;
    const stemY1 = dir === "up" ? tipY + head : tipY - head;
    const stemY2 = dir === "up" ? tipY + head + stem : tipY - head - stem;

    return (
      <g>
        {/* subtle outline for contrast */}
        <path
          d={headPath}
          fill={color}
          stroke="rgba(0,0,0,0.55)"
          strokeWidth={1.2}
          opacity={0.98}
        />
        <line
          x1={x}
          y1={stemY1}
          x2={x}
          y2={stemY2}
          stroke={color}
          strokeWidth={1.7}
          strokeLinecap="round"
          opacity={0.98}
        />
      </g>
    );
  };

  const markerAt = (
    idx: number,
    label: string,
    place: "above" | "below",
    dir: "up" | "down",
    color: string
  ) => {
    if (idx < 0 || idx >= N) return null;
    const cx = xForIndex(idx);
    const { h, l } = ohlc(baseData[idx]);
    if (h == null || l == null) return null;

    // Keep marker within plot bounds while still hugging the candle.
    const yHi = yForPrice(h);
    const yLo = yForPrice(l);

    const tipY =
      place === "below"
        ? clamp(yLo + 4, plot.y + 6, plot.y + plot.h - 6)
        : clamp(yHi - 4, plot.y + 6, plot.y + plot.h - 6);

    const textY = place === "below" ? tipY + 18 : tipY - 12;

    return (
      <g>
        {arrow(cx, tipY, dir, color)}
        <text
          x={cx}
          y={textY}
          fill={color}
          fontSize={8}
          textAnchor="middle"
          fontFamily="ui-sans-serif, system-ui"
          fontWeight={650}
          style={{
            paintOrder: "stroke",
            stroke: "rgba(0,0,0,0.75)",
            strokeWidth: 3,
          }}
        >
          {label}
        </text>
      </g>
    );
  };
  // Tooltip data
  const hovered = React.useMemo(() => {
    if (hoverI == null || hoverI < 0 || hoverI >= N) return null;
    const c = baseData[hoverI];
    if (!c) return null;
    const { o, h, l, c: cl } = ohlc(c);
    const tm = candleTimeMs(c);
    return { idx: hoverI, o, h, l, c: cl, tm };
  }, [hoverI, baseData, N]);

  const timeLabel = (ms: number | null) => {
    if (ms == null) return "";
    const d = new Date(ms);
    // parseMode exists in the app; we keep it simple here
    return `${d.toLocaleDateString()} ${d.toLocaleTimeString([], {
      hour: "2-digit",
      minute: "2-digit",
    })}`;
  };

  const axisTimeLabel = (ms: number | null) => {
    if (ms == null) return "";
    const d = new Date(ms);
    const baseOptions: Intl.DateTimeFormatOptions = {
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    };
    if (String(parseMode || "").toLowerCase() === "utc") {
      baseOptions.timeZone = "UTC";
    }
    return d.toLocaleTimeString([], baseOptions);
  };

  const xAxisTicks = (() => {
    if (!viewData.length) return [];
    const maxTicks = Math.min(6, Math.max(3, Math.floor(viewData.length / 30) + 2));
    const out: Array<{ key: string; x: number; label: string }> = [];
    let lastX = -Infinity;

    for (let k = 0; k < maxTicks; k++) {
      const idxInView =
        maxTicks <= 1
          ? 0
          : Math.round((k * (viewData.length - 1)) / (maxTicks - 1));
      const point = viewData[idxInView];
      if (!point) continue;
      const ms = candleTimeMs(point.c);
      const label = axisTimeLabel(ms);
      if (!label) continue;
      const x = xForIndex(point.i);
      if (x - lastX < 64 && k !== maxTicks - 1) continue;

      out.push({
        key: `${point.i}-${ms ?? "na"}`,
        x,
        label,
      });
      lastX = x;
    }
    return out;
  })();

  // Styling
  const bg = "rgba(0,0,0,0.92)";
  const grid = "rgba(255,255,255,0.10)";
  const txt = "rgba(255,255,255,0.86)";
  const buyCol = "rgba(52,211,153,0.95)";
  const sellCol = "rgba(248,113,113,0.95)";
  const candleUp = "rgba(52,211,153,0.92)";
  const candleDn = "rgba(248,113,113,0.92)";

  // guard
  if (N === 0) {
    return (
      <div
        style={{
          padding: 14,
          borderRadius: 14,
          border: "1px solid rgba(255,255,255,0.10)",
          background: "rgba(0,0,0,0.35)",
        }}
      >
        <div style={{ color: "rgba(255,255,255,0.75)", fontSize: 13 }}>
          No candles available for this trade.
        </div>
      </div>
    );
  }

  // Visible entry/exit (only draw if within view)
  const entryInView =
    entryIdx != null &&
    entryIdx >= viewData[0].i &&
    entryIdx <= viewData[viewData.length - 1].i;
  const exitInView =
    exitIdx != null &&
    exitIdx >= viewData[0].i &&
    exitIdx <= viewData[viewData.length - 1].i;

  const entryX = entryInView ? xForIndex(entryIdx!) : null;
  const exitX = exitInView ? xForIndex(exitIdx!) : null;

  return (
    <div
      ref={wrapRef}
      style={{
        width: "100%",
        borderRadius: 16,
        border: "1px solid rgba(255,255,255,0.10)",
        background: "rgba(0,0,0,0.35)",
        padding: 12,
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "baseline",
          justifyContent: "space-between",
          marginBottom: 10,
        }}
      >
        <div
          style={{
            color: "rgba(255,255,255,0.92)",
            fontWeight: 700,
            fontSize: 14,
          }}
        >
          Trade Candlesticks
          <span
            style={{
              marginLeft: 10,
              fontWeight: 500,
              fontSize: 12,
              color: "rgba(255,255,255,0.62)",
            }}
          >
            drag to pan • scroll to zoom • double-click to reset
          </span>
        </div>
        <div style={{ color: "rgba(255,255,255,0.62)", fontSize: 12 }}>
          Showing {viewData.length} / {N} candles
        </div>
      </div>

      <svg
        viewBox={`0 0 ${W} ${H}`}
        preserveAspectRatio="none"
        style={{
          width: "100%",
          height: H,
          display: "block",
          borderRadius: 12,
          background: bg,
        }}
        onMouseMove={onMouseMove}
        onMouseLeave={onMouseLeave}
        onMouseDown={onMouseDown}
        onMouseUp={onMouseUp}
        onWheel={onWheel}
        onDoubleClick={onDoubleClick}
      >
        {/* Plot background */}
        <rect x={0} y={0} width={W} height={H} fill={bg} />

        {/* Grid */}
        {Array.from({ length: 6 }).map((_, k) => {
          const y = plot.y + (plot.h * k) / 5;
          return (
            <line
              key={`gy-${k}`}
              x1={plot.x}
              y1={y}
              x2={plot.x + plot.w}
              y2={y}
              stroke={grid}
              strokeDasharray="4 6"
            />
          );
        })}
        {Array.from({ length: 8 }).map((_, k) => {
          const x = plot.x + (plot.w * k) / 7;
          return (
            <line
              key={`gx-${k}`}
              x1={x}
              y1={plot.y}
              x2={x}
              y2={plot.y + plot.h}
              stroke={grid}
              strokeDasharray="4 6"
            />
          );
        })}

        {/* Bottom time axis */}
        <line
          x1={plot.x}
          y1={plot.y + plot.h}
          x2={plot.x + plot.w}
          y2={plot.y + plot.h}
          stroke="rgba(255,255,255,0.22)"
        />
        {xAxisTicks.map((tick, idx) => (
          <g key={tick.key}>
            <line
              x1={tick.x}
              y1={plot.y + plot.h}
              x2={tick.x}
              y2={plot.y + plot.h + 4}
              stroke="rgba(255,255,255,0.30)"
            />
            <text
              x={tick.x}
              y={plot.y + plot.h + 17}
              fill="rgba(255,255,255,0.68)"
              fontSize={11}
              fontFamily="ui-sans-serif, system-ui"
              textAnchor={
                idx === 0
                  ? "start"
                  : idx === xAxisTicks.length - 1
                    ? "end"
                    : "middle"
              }
            >
              {tick.label}
            </text>
          </g>
        ))}

        {/* Entry / TP / SL */}
        {entryPrice != null ? (
          <g>
            <line
              x1={plot.x}
              y1={yForPrice(entryPrice)}
              x2={plot.x + plot.w}
              y2={yForPrice(entryPrice)}
              stroke="#ffffff"
              opacity={0.92}
            />
            <text
              x={plot.x + 8}
              y={yForPrice(entryPrice) - 6}
              fill="#ffffff"
              fontSize={12}
              fontFamily="ui-sans-serif, system-ui"
            >
              Entry {fmt2(entryPrice)}
            </text>
          </g>
        ) : null}
        {tp != null ? (
          <g>
            <line
              x1={plot.x}
              y1={yForPrice(tp)}
              x2={plot.x + plot.w}
              y2={yForPrice(tp)}
              stroke={buyCol}
              strokeDasharray="6 6"
              opacity={0.9}
            />
            <text
              x={plot.x + 8}
              y={yForPrice(tp) - 6}
              fill={buyCol}
              fontSize={12}
              fontFamily="ui-sans-serif, system-ui"
            >
              TP {fmt2(tp)}
            </text>
          </g>
        ) : null}
        {sl != null ? (
          <g>
            <line
              x1={plot.x}
              y1={yForPrice(sl)}
              x2={plot.x + plot.w}
              y2={yForPrice(sl)}
              stroke={sellCol}
              strokeDasharray="6 6"
              opacity={0.9}
            />
            <text
              x={plot.x + 8}
              y={yForPrice(sl) - 6}
              fill={sellCol}
              fontSize={12}
              fontFamily="ui-sans-serif, system-ui"
            >
              SL {fmt2(sl)}
            </text>
          </g>
        ) : null}

        {/* Candles */}
        {viewData.map(({ c, i }) => {
          const { o, h, l, c: cl } = ohlc(c);
          if (o == null || h == null || l == null || cl == null) return null;
          const up = cl >= o;
          const col = up ? candleUp : candleDn;

          const cx = xForIndex(i);
          const yO = yForPrice(o);
          const yC = yForPrice(cl);
          const yH = yForPrice(h);
          const yL = yForPrice(l);

          const bodyY = Math.min(yO, yC);
          const bodyH = Math.max(2, Math.abs(yC - yO));
          const wickX = cx;
          const bodyX = cx - candleWidth / 2;

          const isHovered = hoverI === i;

          return (
            <g key={`c-${i}`}>
              {/* wick */}
              <line
                x1={wickX}
                y1={yH}
                x2={wickX}
                y2={yL}
                stroke={col}
                strokeWidth={2}
                opacity={0.95}
              />
              {/* body */}
              <rect
                x={bodyX}
                y={bodyY}
                width={candleWidth}
                height={bodyH}
                fill={col}
                opacity={0.92}
                rx={1.5}
              />
              {/* hover outline */}
              {isHovered ? (
                <rect
                  x={bodyX - 2}
                  y={bodyY - 2}
                  width={candleWidth + 4}
                  height={bodyH + 4}
                  fill="none"
                  stroke="rgba(255,255,255,0.55)"
                  strokeWidth={1}
                  rx={2}
                />
              ) : null}
            </g>
          );
        })}

        {/* Entry / Exit markers (hug the candle: above/below) */}
        {entryInView
          ? markerAt(
              entryIdx!,
              `Entry ${entrySide}`,
              isLong ? "below" : "above",
              isLong ? "up" : "down",
              isLong ? buyCol : sellCol
            )
          : null}
        {exitInView && exitIdx != null
          ? markerAt(
              exitIdx,
              `Exit ${exitSide}`,
              isLong ? "above" : "below",
              isLong ? "down" : "up",
              isLong ? sellCol : buyCol
            )
          : null}

        {/* Crosshair */}

        {mouseXY &&
        mouseXY.x >= plot.x &&
        mouseXY.x <= plot.x + plot.w &&
        mouseXY.y >= plot.y &&
        mouseXY.y <= plot.y + plot.h ? (
          <g>
            <line
              x1={mouseXY.x}
              y1={plot.y}
              x2={mouseXY.x}
              y2={plot.y + plot.h}
              stroke="rgba(255,255,255,0.22)"
              strokeDasharray="4 6"
            />
            <line
              x1={plot.x}
              y1={mouseXY.y}
              x2={plot.x + plot.w}
              y2={mouseXY.y}
              stroke="rgba(255,255,255,0.22)"
              strokeDasharray="4 6"
            />
          </g>
        ) : null}

        {/* Tooltip */}
        {hovered && mouseXY
          ? (() => {
              const boxW = 260;
              const boxH = 90;
              let bx = mouseXY.x + 12;
              let by = mouseXY.y + 12;
              if (bx + boxW > W - 10) bx = mouseXY.x - boxW - 12;
              if (by + boxH > H - 10) by = mouseXY.y - boxH - 12;

              return (
                <g>
                  <rect
                    x={bx}
                    y={by}
                    width={boxW}
                    height={boxH}
                    rx={10}
                    fill="rgba(15,15,15,0.92)"
                    stroke="rgba(255,255,255,0.12)"
                  />
                  <text
                    x={bx + 12}
                    y={by + 22}
                    fill={txt}
                    fontSize={12}
                    fontFamily="ui-sans-serif, system-ui"
                    opacity={0.9}
                  >
                    {timeLabel(hovered.tm)}
                  </text>
                  <text
                    x={bx + 12}
                    y={by + 44}
                    fill={txt}
                    fontSize={12}
                    fontFamily="ui-sans-serif, system-ui"
                    opacity={0.92}
                  >
                    O {fmt2(hovered.o)} H {fmt2(hovered.h)}
                  </text>
                  <text
                    x={bx + 12}
                    y={by + 64}
                    fill={txt}
                    fontSize={12}
                    fontFamily="ui-sans-serif, system-ui"
                    opacity={0.92}
                  >
                    L {fmt2(hovered.l)} C {fmt2(hovered.c)}
                  </text>
                  <text
                    x={bx + 12}
                    y={by + 84}
                    fill="rgba(255,255,255,0.55)"
                    fontSize={11}
                    fontFamily="ui-sans-serif, system-ui"
                  >
                    idx {hovered.idx}
                  </text>
                </g>
              );
            })()
          : null}
      </svg>
    </div>
  );
}

// --- Trade Candlestick Chart (TradingView Lightweight Charts when available) ---
// We *attempt* to use `lightweight-charts`. If it isn't installed in the environment,
// we automatically fall back to the SVG implementation above.
function TradeCandlestickChart(props: {
  trade: any;
  candles: any[];
  interval?: string;
  parseMode?: "utc" | "local" | string;
  tpDist?: number;
  slDist?: number;
  heightPx?: number;
}) {
  const [lwMod, setLwMod] = React.useState<any | false | null>(null);

  React.useEffect(() => {
    let alive = true;
    import("lightweight-charts")
      .then((m) => alive && setLwMod(m))
      .catch(() => alive && setLwMod(false));
    return () => {
      alive = false;
    };
  }, []);

  // While loading OR if missing, render SVG (so the UI never goes blank).
  if (!lwMod || lwMod === false) return <TradeCandlestickChartSVG {...props} />;

  return <TradeCandlestickChartLightweight {...props} lw={lwMod} />;
}

function TradeCandlestickChartLightweight({
  trade,
  candles,
  interval,
  tpDist,
  slDist,
  heightPx = 420,
  lw,
}: {
  trade: any;
  candles: any[];
  interval?: string;
  tpDist?: number;
  slDist?: number;
  heightPx?: number;
  lw: any;
}) {
  const containerRef = React.useRef<HTMLDivElement | null>(null);
  const chartRef = React.useRef<any>(null);
  const seriesRef = React.useRef<any>(null);
  const resizeObserverRef = React.useRef<ResizeObserver | null>(null);
  const priceLinesRef = React.useRef<any[]>([]);
  const lastTradeViewKeyRef = React.useRef<string | null>(null);

  const num = (v: any) => {
    const n =
      typeof v === "number" ? v : v != null && v !== "" ? Number(v) : NaN;
    return Number.isFinite(n) ? n : null;
  };

  const baseData = Array.isArray(candles) ? candles : [];
  const N = baseData.length;

  const toSec = (t: any) => {
    if (t == null) return null;
    if (typeof t === "number")
      return t > 1e12 ? Math.floor(t / 1000) : Math.floor(t);
    const d = new Date(String(t));
    const ms = d.getTime();
    return Number.isFinite(ms) ? Math.floor(ms / 1000) : null;
  };

  const intervalMin = parseIntervalToMinutes(interval ?? "") ?? 15;
  const intervalSec = Math.max(60, Math.round(intervalMin * 60));

  const resolveIdx = (obj: any, keys: string[]) => {
    for (const k of keys) {
      const v = num(obj?.[k]);
      if (v != null) return Math.max(0, Math.min(N - 1, Math.round(v)));
    }
    return null;
  };

  const entryIdx =
    resolveIdx(trade, [
      "entryIndex",
      "entryIdx",
      "entryBarIndex",
      "entryBar",
      "entryCandleIndex",
      "entry_i",
    ]) ?? 0;
  const exitIdx =
    resolveIdx(trade, [
      "exitIndex",
      "exitIdx",
      "exitBarIndex",
      "exitBar",
      "exitCandleIndex",
      "exit_i",
    ]) ?? null;

  const entryTimeSec = toSec(
    (trade as any)?.entryTime ??
      (trade as any)?.entryTs ??
      (trade as any)?.openTime
  );

  const candleTimeSec = (c: any) =>
    toSec(c?.t ?? c?.time ?? c?.timestamp ?? c?.ts ?? c?.date ?? c?.datetime);

  const hasTimes = React.useMemo(() => {
    for (let i = 0; i < N; i++) {
      if (candleTimeSec(baseData[i]) != null) return true;
    }
    return false;
  }, [baseData, N]);

  const data = React.useMemo(() => {
    const out: any[] = [];
    if (N === 0) return out;

    const origin =
      entryTimeSec != null
        ? entryTimeSec - entryIdx * intervalSec
        : Math.floor(Date.now() / 1000) - N * intervalSec;

    for (let i = 0; i < N; i++) {
      const c = baseData[i] || {};
      const o = num(c?.o ?? c?.open);
      const h = num(c?.h ?? c?.high);
      const l = num(c?.l ?? c?.low);
      const cl = num(c?.c ?? c?.close);
      if (o == null || h == null || l == null || cl == null) continue;
      const t = hasTimes ? candleTimeSec(c) : origin + i * intervalSec;
      if (t == null) continue;
      out.push({ time: t, open: o, high: h, low: l, close: cl, __i: i });
    }
    return out;
  }, [baseData, N, hasTimes, entryTimeSec, entryIdx, intervalSec]);

  const priceSnapshot = React.useMemo(
    () => resolveTradePnlSnapshot(trade, 1, baseData, tpDist, slDist),
    [trade, baseData, tpDist, slDist]
  );
  const isLong = priceSnapshot.dir !== -1;

  const entrySide = isLong ? "Buy" : "Sell";
  const exitSide = isLong ? "Sell" : "Buy";

  const entryPrice =
    priceSnapshot.entryPrice ??
    num(
      (trade as any)?.entryPrice ??
        (trade as any)?.entry ??
        (trade as any)?.openPrice
    ) ??
    (data[Math.min(entryIdx, Math.max(0, data.length - 1))]
      ? num(data[Math.min(entryIdx, data.length - 1)].open)
      : null);

  const exitPrice =
    priceSnapshot.exitPrice ??
    num(
      (trade as any)?.exitPrice ??
        (trade as any)?.exit ??
        (trade as any)?.closePrice
    ) ??
    (exitIdx != null && data[Math.min(exitIdx, Math.max(0, data.length - 1))]
      ? num(data[Math.min(exitIdx, data.length - 1)].close)
      : null);

  const tp = priceSnapshot.tpPrice;
  const sl = priceSnapshot.slPrice;

  const height = Math.max(320, Math.min(560, heightPx));
  const heightRef = React.useRef(height);
  heightRef.current = height;

  const tradeLenRaw =
    num(
      (trade as any)?.bars ??
        (trade as any)?.barsHeld ??
        (trade as any)?.barCount ??
        (trade as any)?.lenBars
    ) ?? (exitIdx != null ? Math.max(1, exitIdx - entryIdx + 1) : 30);
  const initialWin = Math.max(30, Math.ceil(tradeLenRaw * 3));
  const initialStart = Math.max(0, entryIdx - Math.floor(initialWin * 0.35));
  const initialEnd = Math.min(
    Math.max(0, N - 1),
    initialStart + initialWin - 1
  );

  const tradeViewKey = React.useMemo(() => {
    const id =
      (trade as any)?.uid ??
      (trade as any)?.id ??
      (trade as any)?.tradeId ??
      (trade as any)?.entryTime ??
      (trade as any)?.time ??
      "";
    const exitKey =
      (trade as any)?.exitTime ??
      (trade as any)?.exitIndex ??
      (trade as any)?.closeIndex ??
      "open";
    return `${String(id)}|${entryIdx}|${exitIdx ?? "open"}|${String(exitKey)}`;
  }, [trade, entryIdx, exitIdx]);

  React.useEffect(() => {
    if (!containerRef.current) return;
    if (!lw?.createChart) return;

    const el = containerRef.current;
    const { createChart } = lw;
    const CrosshairMode = lw?.CrosshairMode;
    el.innerHTML = "";

    const chart = createChart(el, {
      width: el.clientWidth || 900,
      height: heightRef.current,
      layout: {
        background: { type: "solid", color: "#000" },
        textColor: "rgba(255,255,255,0.70)",
        fontFamily:
          "ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial",
      },
      grid: {
        vertLines: { color: "rgba(255,255,255,0.06)" },
        horzLines: { color: "rgba(255,255,255,0.06)" },
      },
      crosshair: CrosshairMode
        ? {
            mode: CrosshairMode.Normal,
            vertLine: { color: "rgba(255,255,255,0.25)", width: 1 },
            horzLine: { color: "rgba(255,255,255,0.18)", width: 1 },
          }
        : undefined,
      rightPriceScale: {
        borderColor: "rgba(255,255,255,0.10)",
        scaleMargins: { top: 0.1, bottom: 0.1 },
      },
      timeScale: {
        borderColor: "rgba(255,255,255,0.10)",
        timeVisible: true,
        secondsVisible: false,
      },
      handleScale: {
        axisPressedMouseMove: true,
        mouseWheel: true,
        pinch: true,
      },
      handleScroll: {
        mouseWheel: true,
        pressedMouseMove: true,
        horzTouchDrag: true,
        vertTouchDrag: true,
      },
    });

    const series = chart.addCandlestickSeries({
      upColor: "#34d399",
      downColor: "#fb7185",
      wickUpColor: "#34d399",
      wickDownColor: "#fb7185",
      borderVisible: false,
      priceLineVisible: false,
    });

    chartRef.current = chart;
    seriesRef.current = series;
    priceLinesRef.current = [];

    const ro = new ResizeObserver(() => {
      chart.applyOptions({ width: el.clientWidth || 900, height: heightRef.current });
    });
    ro.observe(el);
    resizeObserverRef.current = ro;

    return () => {
      resizeObserverRef.current?.disconnect();
      resizeObserverRef.current = null;
      priceLinesRef.current = [];
      seriesRef.current = null;
      chartRef.current = null;
      chart.remove();
    };
  }, [lw]);

  React.useEffect(() => {
    chartRef.current?.applyOptions({ height });
  }, [height]);

  React.useEffect(() => {
    if (!seriesRef.current) return;
    seriesRef.current.setData(data);
  }, [data]);

  React.useEffect(() => {
    const series = seriesRef.current;
    if (!series) return;
    const LineStyle = lw?.LineStyle;

    const entryT = data[Math.min(entryIdx, Math.max(0, data.length - 1))]?.time;
    const exitT =
      exitIdx != null
        ? data[Math.min(exitIdx, Math.max(0, data.length - 1))]?.time
        : null;

    const markers: any[] = [];
    if (entryT != null) {
      markers.push({
        time: entryT,
        position: isLong ? "belowBar" : "aboveBar",
        color: isLong ? "#34d399" : "#fb7185",
        shape: isLong ? "arrowUp" : "arrowDown",
        text: `Entry ${entrySide}`,
      });
    }
    if (exitT != null) {
      markers.push({
        time: exitT,
        position: isLong ? "aboveBar" : "belowBar",
        color: isLong ? "#fb7185" : "#34d399",
        shape: isLong ? "arrowDown" : "arrowUp",
        text: `Exit ${exitSide}`,
      });
    }
    if (typeof series.setMarkers === "function") {
      series.setMarkers(markers);
    }

    if (typeof series.removePriceLine === "function") {
      for (const line of priceLinesRef.current) {
        series.removePriceLine(line);
      }
    }
    priceLinesRef.current = [];

    const addLine = (
      price: number | null,
      color: string,
      title: string,
      lineStyle: number
    ) => {
      if (price == null || typeof series.createPriceLine !== "function") return;
      const line = series.createPriceLine({
        price,
        color,
        lineWidth: 1,
        lineStyle,
        axisLabelVisible: true,
        title,
      });
      if (line) priceLinesRef.current.push(line);
    };

    addLine(entryPrice, "#ffffff", "Entry", LineStyle ? LineStyle.Solid : 0);
    addLine(tp, "#34d399", "TP", LineStyle ? LineStyle.Dashed : 2);
    addLine(sl, "#fb7185", "SL", LineStyle ? LineStyle.Dashed : 2);
  }, [lw, data, entryIdx, exitIdx, isLong, entrySide, exitSide, entryPrice, tp, sl]);

  React.useEffect(() => {
    const chart = chartRef.current;
    if (!chart || data.length === 0) return;
    if (lastTradeViewKeyRef.current === tradeViewKey) return;
    lastTradeViewKeyRef.current = tradeViewKey;

    const safeStart = Math.min(initialStart, Math.max(0, data.length - 1));
    const safeEnd = Math.min(
      Math.max(safeStart, initialEnd),
      Math.max(0, data.length - 1)
    );
    const startT = data[safeStart]?.time;
    const endT = data[safeEnd]?.time;

    if (startT != null && endT != null && chart.timeScale().setVisibleRange) {
      chart.timeScale().setVisibleRange({ from: startT, to: endT });
    } else {
      chart.timeScale().fitContent();
    }
  }, [data, initialStart, initialEnd, tradeViewKey]);

  return (
    <div
      style={{
        border: "1px solid rgba(255,255,255,0.10)",
        background: "rgba(0,0,0,0.80)",
        borderRadius: 18,
        overflow: "hidden",
        boxShadow: "0 18px 60px rgba(0,0,0,0.55) inset",
      }}
    >
      <div
        style={{
          padding: "10px 14px",
          display: "flex",
          alignItems: "baseline",
          justifyContent: "space-between",
          borderBottom: "1px solid rgba(255,255,255,0.06)",
        }}
      >
        <div
          style={{
            fontSize: 14,
            fontWeight: 900,
            color: "rgba(255,255,255,0.92)",
          }}
        >
          Trade Candlesticks
          <span
            style={{
              marginLeft: 10,
              fontSize: 12,
              fontWeight: 700,
              opacity: 0.65,
            }}
          >
            drag to pan · scroll to zoom · double-click to reset
          </span>
        </div>
        <div style={{ fontSize: 12, opacity: 0.65 }}>
          Showing {data.length} candles
        </div>
      </div>
      <div
        style={{
          width: "100%",
          height,
        }}
        ref={containerRef}
      />
    </div>
  );
}
// --- End Trade Candlestick Chart ---

const ChevronDown = ({ size = 18, style, className }) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 24 24"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    style={style}
    className={className}
  >
    <path
      d="M6 9l6 6 6-6"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
  </svg>
);
function parseIntervalToMinutes(s) {
  if (!s) return 1;
  const m = s.toLowerCase().trim();
  const numMatch = m.match(/\d+/);
  const n = numMatch ? Number(numMatch[0]) : 1;
  if (m.includes("min")) return n;
  if (m.includes("hour") || m.includes("hr") || m.includes("h")) return n * 60;
  if (m.includes("day") || m.includes("d")) return n * 1440;
  return 1;
}
function decimateEvery(arr, maxN) {
  const n = arr ? arr.length : 0;
  if (!n || n <= maxN) return arr || [];
  const step = Math.ceil(n / maxN);
  const out = [];
  for (let i = 0; i < n; i += step) out.push(arr[i]);
  if (out[out.length - 1] !== arr[n - 1]) out.push(arr[n - 1]);
  return out;
}

function clampInt(v, lo, hi) {
  const n = Math.floor(Number(v) || 0);
  return Math.min(hi, Math.max(lo, n));
}

const checklistLabelMap = {
  Momentum: {
    buy: ["Strong uptrend", "Recent pullback", "Above mid‑range"],
    sell: ["Strong downtrend", "Recent rally", "Below mid‑range"],
  },
  "Mean Reversion": {
    buy: ["Oversold (low range)", "Bounce from low", "Weak or flat trend"],
    sell: ["Overbought (high range)", "Dip from high", "Weak or flat trend"],
  },
  Seasons: {
    buy: ["Seasonal bias bullish", "Uptrend confirmation", "Not overbought"],
    sell: ["Seasonal bias bearish", "Downtrend confirmation", "Not oversold"],
  },
  "Time of Day": {
    buy: ["Day session start", "Uptrend confirmation", "Adequate volatility"],
    sell: [
      "Night session start",
      "Downtrend confirmation",
      "Adequate volatility",
    ],
  },
  Fibonacci: {
    buy: ["Uptrend", "Retracement to lower zone", "No strong down spikes"],
    sell: ["Downtrend", "Retracement to upper zone", "No strong up spikes"],
  },
  "Support / Resistance": {
    buy: ["Near support", "Bullish reversal", "Sufficient range"],
    sell: ["Near resistance", "Bearish reversal", "Sufficient range"],
  },
};

function canonicalModelName(name: any): string {
  const s = String(name ?? "").toLowerCase();
  const norm = s.replace(/[^a-z0-9]+/g, " ").trim();
  if (!norm) return String(name ?? "");
  if (norm.includes("momentum")) return "Momentum";
  if (norm.includes("mean") && norm.includes("reversion"))
    return "Mean Reversion";
  if (norm.includes("season")) return "Seasons";
  if (norm.includes("time") && norm.includes("day")) return "Time of Day";
  if (norm.includes("fibo")) return "Fibonacci";
  if (
    norm.includes("support") ||
    norm.includes("resistance") ||
    norm.includes("sr")
  )
    return "Support / Resistance";
  // If this is an "AI Model" wrapper, try to fall back later (caller can pass origModel).
  if (norm.includes("ai") && norm.includes("model")) return "AI Model";
  return String(name ?? "");
}
function translateChecklist(model, items, type) {
  const m = checklistLabelMap[model];
  if (!m) return items;
  const arr = m[type];
  return items.map((it, idx) => ({
    label: arr && arr[idx] ? arr[idx] : it.label,
    ok: it.ok,
  }));
}
function humanizeDurationMinutes(totalMin: number) {
  const minutes = Math.max(0, Math.round(totalMin));
  const parts: string[] = [];
  const days = Math.floor(minutes / 1440);
  const remAfterDays = minutes % 1440;
  const hours = Math.floor(remAfterDays / 60);
  const mins = remAfterDays % 60;

  const push = (n: number, w: string) => {
    if (n > 0) parts.push(`${n} ${w}${n === 1 ? "" : "s"}`);
  };
  push(days, "Day");
  push(hours, "Hour");
  push(mins, "Minute");

  if (!parts.length) return "0 Minutes";
  if (parts.length === 1) return parts[0];
  if (parts.length === 2) return `${parts[0]} and ${parts[1]}`;
  return `${parts.slice(0, -1).join(", ")} and ${parts[parts.length - 1]}`;
}

function PerTradeMiniChart({
  data,
  yDomain,
  entryPrice,
  tpPrice,
  slPrice,
  side,
  usdPerUnit, // DOLLARS_PER_UNIT * lotSize
  isOpen, // whether the row is expanded
}: {
  data: Array<{
    bar: number;
    price: number;
    high: number;
    low: number;
    up: number | null;
    down: number | null;
    flat: number | null;
    ts?: number; // <-- add
    candIdx?: number; // <-- add
    relCand?: number; // <-- add this
  }>;
  yDomain: [number | "auto", number | "auto"];
  entryPrice: number;
  tpPrice: number | null;
  slPrice: number | null;
  side: "BUY" | "SELL";
  usdPerUnit: number;
  isOpen: boolean;
}) {
  // 0→X reveal animation
  const [reveal, setReveal] = React.useState(0);
  React.useEffect(() => {
    let raf = 0;
    if (!isOpen) {
      setReveal(0);
      return () => cancelAnimationFrame(raf);
    }
    const D = 1600; // ms
    const t0 = performance.now();
    const tick = (t: number) => {
      const p = Math.min(1, (t - t0) / D);
      setReveal(p);
      if (p < 1) raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [isOpen]);

  const clipId = React.useId();
  const glowId = React.useId();

  const dir = side === "BUY" ? 1 : -1;
  // was: const fmt3 = (x: number) => (Number.isFinite(x) ? x.toFixed(3) : "–");
  const fmt3 = (x: number) =>
    Number.isFinite(x)
      ? x.toLocaleString(undefined, { maximumFractionDigits: 3 })
      : "–";

  const fmtUSD3 = (x: number) =>
    `${x >= 0 ? "+" : "-"}$${Math.abs(x).toFixed(3)}`;
  const pnl = (p: number) => (p - entryPrice) * dir * usdPerUnit;

  return (
    <div className="h-full bg-neutral-950 rounded-xl border border-neutral-800 overflow-hidden">
      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart
          data={data}
          margin={{ top: 10, right: 24, left: 12, bottom: 10 }}
        >
          <defs>
            {/* soft glow for the lines */}
            <filter id={glowId} x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="2" result="blur" />
              <feMerge>
                <feMergeNode in="blur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>

            {/* 0→X reveal mask (objectBoundingBox units: width is 0..1) */}
            <clipPath id={clipId} clipPathUnits="objectBoundingBox">
              <rect x="0" y="0" width={reveal} height="1" />
            </clipPath>
          </defs>

          <XAxis
            dataKey="bar"
            type="number"
            domain={[-1, "dataMax"]}
            tickFormatter={(v: number) => (v === -1 ? "-1" : String(v))}
            label={{
              value: "Minutes since entry",
              position: "insideBottomRight",
              offset: -4,
              fill: "#9ca3af",
              fontSize: 11,
            }}
            tick={{ fontSize: 11, fill: "#9ca3af" }}
            axisLine={false}
            tickLine={false}
          />

          <YAxis
            type="number"
            domain={yDomain as any}
            tickFormatter={(v: number) =>
              Number.isFinite(v)
                ? v.toLocaleString(undefined, { maximumFractionDigits: 3 })
                : ""
            }
            tick={{ fontSize: 11, fill: "#9ca3af" }}
            axisLine={false}
            tickLine={false}
          />

          {/* guides */}
          <ReferenceLine
            y={entryPrice}
            stroke="#a3a3a3"
            strokeDasharray="4 6"
          />
          {Number.isFinite(tpPrice as number) && (
            <ReferenceLine
              y={tpPrice as number}
              stroke="#34d399"
              strokeDasharray="4 6"
            />
          )}
          {Number.isFinite(slPrice as number) && (
            <ReferenceLine
              y={slPrice as number}
              stroke="#f87171"
              strokeDasharray="4 6"
            />
          )}

          <Tooltip
            content={({ active, payload }) => {
              if (!active || !payload?.length) return null;
              const row = payload[0].payload as {
                bar: number; // minutes since entry (>=0) in minute mode
                price: number;
                high: number;
                low: number;
                ts?: number; // absolute ms (UTC)
                relCand?: number; // 0-based bars since entry
              };

              // --- date & time (UTC) ---
              // --- date & time (consistent with upstream shift) ---
              const ts0 = typeof row.ts === "number" ? row.ts : Date.now();
              // Rows are already shifted for Local mode upstream; use ts0 directly here
              const ts = ts0;

              const d = new Date(ts);

              const mm = String(d.getUTCMonth() + 1).padStart(2, "0");
              const dd = String(d.getUTCDate()).padStart(2, "0");
              const yyyy = d.getUTCFullYear();
              const h24 = d.getUTCHours();
              const m = String(d.getUTCMinutes()).padStart(2, "0");
              const ampm = h24 >= 12 ? "PM" : "AM";
              const h12 = h24 % 12 || 12;

              // --- candles & minutes in ---
              const candleCount =
                typeof row.relCand === "number" && row.relCand >= 0
                  ? row.relCand + 1
                  : 0;
              const minutesIn =
                typeof row.bar === "number" && row.bar >= 0
                  ? Math.round(row.bar)
                  : 0;
              const minutesLabel = humanizeDurationMinutes(minutesIn);
              const plural = (n: number, w: string) =>
                `${n} ${w}${n === 1 ? "" : "s"}`;

              // --- PnL calcs (unchanged) ---
              const closeP = pnl(row.price);
              const highP = pnl(row.high);
              const lowP = pnl(row.low);
              const color = (v: number) =>
                v > 0 ? "#34d399" : v < 0 ? "#f87171" : "#e5e7eb";

              return (
                <div
                  style={{
                    background: "#000",
                    border: "1px solid #262626",
                    borderRadius: 12,
                    padding: "8px 10px",
                    color: "#e5e7eb",
                    fontSize: 12,
                  }}
                >
                  {/* Header lines */}
                  <div
                    style={{ opacity: 0.9, marginBottom: 4, fontWeight: 600 }}
                  >
                    {mm}/{dd}/{yyyy} | {h12}:{m}
                    {ampm}
                  </div>
                  <div style={{ opacity: 0.8, marginBottom: 8 }}>
                    {plural(candleCount, "Candle")} | {minutesLabel} In
                  </div>

                  {/* Price block */}
                  <div>
                    Close: <b>{fmt3(row.price)}</b>
                  </div>
                  <div>
                    High: <b>{fmt3(row.high)}</b>
                  </div>
                  <div>
                    Low: <b>{fmt3(row.low)}</b>
                  </div>
                  <hr style={{ borderColor: "#262626", margin: "6px 0" }} />
                  <div>
                    Close PnL:{" "}
                    <b style={{ color: color(closeP) }}>{fmtUSD3(closeP)}</b>
                  </div>
                  <div>
                    High&nbsp; PnL:{" "}
                    <b style={{ color: color(highP) }}>{fmtUSD3(highP)}</b>
                  </div>
                  <div>
                    Low&nbsp;&nbsp; PnL:{" "}
                    <b style={{ color: color(lowP) }}>{fmtUSD3(lowP)}</b>
                  </div>
                </div>
              );
            }}
          />

          {/* wipe group: everything inside reveals together 0→X */}
          <g clipPath={`url(#${clipId})`}>
            <Line
              type="monotone"
              dataKey="up"
              stroke="#34d399"
              strokeWidth={3}
              dot={false}
              activeDot={{ r: 6 }}
              style={{ filter: `url(#${glowId})` }}
              isAnimationActive={false}
              connectNulls={false}
            />
            <Line
              type="monotone"
              dataKey="down"
              stroke="#f87171"
              strokeWidth={3}
              dot={false}
              activeDot={{ r: 6 }}
              style={{ filter: `url(#${glowId})` }}
              isAnimationActive={false}
              connectNulls={false}
            />
            <Line
              type="monotone"
              dataKey="flat"
              stroke="#ffffff"
              strokeWidth={3}
              dot={false}
              activeDot={{ r: 6 }}
              style={{ filter: `url(#${glowId})` }}
              isAnimationActive={false}
              connectNulls={false}
            />
          </g>
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
}

function TradeMiniChart({
  trade,
  candles,
  dollarsPerMove,
  interval,
  isOpen,
  parseMode,
  tpDist,
  slDist,
  // calendar per-trade mini chart: keep it tall enough to match the reference UI
  heightPx = 240,
}) {
  const minutesPerBar = parseIntervalToMinutes(interval);

  // local numeric parser (avoids relying on outer-scope helpers)
  const num = (v: any): number | null => {
    if (v == null) return null;
    if (typeof v === "number") return Number.isFinite(v) ? v : null;
    if (typeof v === "string") {
      const s = v.trim();
      if (!s) return null;
      const n = Number(s.replace(/,/g, ""));
      return Number.isFinite(n) ? n : null;
    }
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  };

  const snapshot = useMemo(
    () => resolveTradePnlSnapshot(trade, dollarsPerMove, candles, tpDist, slDist),
    [trade, dollarsPerMove, candles, tpDist, slDist]
  );
  const dir = snapshot.dir === -1 ? -1 : 1;
  const side = (dir === 1 ? "BUY" : "SELL") as "BUY" | "SELL";

  const entryIdx =
    (trade as any).entryIdx ??
    (trade as any).entryIndex ??
    (trade as any).entryBar ??
    (trade as any).iEntry ??
    (trade as any).entry_i;

  const exitIdxRaw =
    (trade as any).exitIdx ??
    (trade as any).exitIndex ??
    (trade as any).exitBar ??
    (trade as any).iExit ??
    (trade as any).exit_i;

  const barsHeld =
    (trade as any).barsHeld ??
    (trade as any).bars ??
    (trade as any).barsInTrade ??
    (trade as any).bars_in_trade;

  const entryIndex = Math.max(0, Number(entryIdx ?? 0) || 0);
  const exitIndex = (() => {
    const v = Number(exitIdxRaw);
    if (Number.isFinite(v)) return Math.max(0, v);
    const bh = Number(barsHeld);
    if (Number.isFinite(bh) && bh > 0)
      return entryIndex + Math.max(0, Math.round(bh));
    return entryIndex;
  })();

  const entryC = candles?.[entryIndex];
  const exitC = candles?.[exitIndex];

  const entryPrice =
    snapshot.entryPrice ??
    num((trade as any).entryPrice) ??
    num((trade as any).openPrice) ??
    num(entryC?.open) ??
    num(entryC?.close) ??
    0;

  // If exitPrice isn't provided, derive from candle close (or PnL if available)
  const pnlUsd = num(
    (trade as any).pnl ??
      (trade as any).realizedPnl ??
      (trade as any).profit ??
      (trade as any).netPnl
  );
  const exitPrice =
    snapshot.exitPrice ??
    num((trade as any).exitPrice) ??
    num((trade as any).closePrice) ??
    num(exitC?.close) ??
    (pnlUsd != null && dollarsPerMove
      ? entryPrice + (pnlUsd / dollarsPerMove) * dir
      : null) ??
    entryPrice;

  const tpPrice = snapshot.tpPrice;
  const slPrice = snapshot.slPrice;

  // Build line-series data (minutes since entry). First point is a pre-bar at bar=-1.
  const data = useMemo(() => {
    const out: any[] = [];
    if (!candles?.length) return out;
    const start = Math.max(0, entryIndex - 1);
    const end = Math.min(candles.length - 1, Math.max(exitIndex, entryIndex));
    const pre = candles[start];
    const prePrice =
      start < entryIndex ? num(pre?.close) ?? entryPrice : entryPrice;

    out.push({
      bar: -1,
      price: prePrice,
      high: prePrice,
      low: prePrice,
      up: prePrice,
      down: null,
      flat: null,
      relCand: -1,
      ts: num(pre?.timeMs ?? pre?.t ?? pre?.time ?? pre?.ts) ?? undefined,
    });

    let prev = prePrice;
    for (let k = entryIndex; k <= end; k++) {
      const c = candles[k];
      const close = num(c?.close) ?? prev;
      const high = num(c?.high) ?? close;
      const low = num(c?.low) ?? close;
      const relCand = k - entryIndex;
      const bar = relCand * minutesPerBar;

      const up = close > prev ? close : null;
      const down = close < prev ? close : null;
      const flat = close === prev ? close : null;

      out.push({
        bar,
        price: close,
        high,
        low,
        up,
        down,
        flat,
        relCand,
        candIdx: k,
        ts: num(c?.timeMs ?? c?.t ?? c?.time ?? c?.ts) ?? undefined,
      });
      prev = close;
    }

    // Stitch colored segments so the line is continuous at direction changes.
    // Each segment line (up/down/flat) needs the prior point as an anchor.
    for (let i = 1; i < out.length; i++) {
      const cur = out[i];
      const prevRow = out[i - 1];
      if (cur.up != null) prevRow.up = prevRow.price;
      if (cur.down != null) prevRow.down = prevRow.price;
      if (cur.flat != null) prevRow.flat = prevRow.price;
    }

    // ensure last point matches exit price if trade provides it
    if (out.length) {
      const last = out[out.length - 1];
      if (Number.isFinite(exitPrice)) {
        last.price = exitPrice;
        last.high = Math.max(last.high ?? exitPrice, exitPrice);
        last.low = Math.min(last.low ?? exitPrice, exitPrice);
        // keep direction key on the last segment
        if (out.length >= 2) {
          const p2 = out[out.length - 2].price;
          last.up = exitPrice > p2 ? exitPrice : null;
          last.down = exitPrice < p2 ? exitPrice : null;
          last.flat = exitPrice === p2 ? exitPrice : null;
        }
      }
    }

    return out;
  }, [candles, entryIndex, exitIndex, minutesPerBar, entryPrice, exitPrice]);

  const yDomain = useMemo(() => {
    if (!data.length) return ["auto", "auto"] as const;
    const lows = data.map((d) => d.low).filter(Number.isFinite) as number[];
    const highs = data.map((d) => d.high).filter(Number.isFinite) as number[];
    if (!lows.length || !highs.length) return ["auto", "auto"] as const;

    let lo = Math.min(...lows);
    let hi = Math.max(...highs);

    if (Number.isFinite(tpPrice as any)) hi = Math.max(hi, tpPrice as number);
    if (Number.isFinite(slPrice as any)) lo = Math.min(lo, slPrice as number);

    const span = Math.max(1e-9, hi - lo);
    const pad = Math.max(span * 0.12, Math.abs(Number(entryPrice)) * 0.002, 1);
    return [lo - pad, hi + pad] as const;
  }, [data, entryPrice, tpPrice, slPrice]);

  return (
    <div style={{ height: heightPx }}>
      <PerTradeMiniChart
        data={data as any}
        yDomain={yDomain as any}
        entryPrice={Number(entryPrice) || 0}
        tpPrice={Number.isFinite(tpPrice as any) ? (tpPrice as number) : null}
        slPrice={Number.isFinite(slPrice as any) ? (slPrice as number) : null}
        side={side}
        usdPerUnit={Number(dollarsPerMove) || 1}
        isOpen={!!isOpen}
      />
    </div>
  );
}

const TWELVE_API_KEY = "139626f1aaa3426a942e411734ecb8c2";
const DEFAULT_SYMBOL = "XAUUSD";
const DEFAULT_INTERVAL = "15min";
const REFRESH_MS = 5 * 60 * 1000;
