    REMAP_OPPOSITE_OUTCOMES = (settings.remapOppositeOutcomes === false) ? false : true;
    DOMAINS = Array.isArray(settings.domains) ? settings.domains.map((s)=>String(s)) : [];
    DOMAIN_SET = (DOMAINS && DOMAINS.length) ? new Set(DOMAINS) : null;


