      if (Number.isFinite(idx)) return idx;

      const raw =
        (n as any).entryTime ??
        (n as any).metaTime ??
        (n as any).time ??
        (n as any).exitTime ??
        "";
      const parsed = raw ? parseDateFromString(String(raw), parseMode) : null;
      const ts = parsed ? parsed.getTime() : NaN;
