  const priceChangeDistributionData = useMemo(() => {
    if (!candles.length) return [];
    const bars = Math.max(1, chunkBars);
    const changes = Array.from({ length: bars }, () => []);
    for (let endIndex = bars - 1; endIndex < candles.length; endIndex++) {
      const startIdx = endIndex - (bars - 1);
      const startCandle = candles[startIdx];
      const startClose =
        startCandle && typeof startCandle.close === "number"
          ? startCandle.close
          : undefined;
      if (startClose === undefined || startClose === 0) continue;
      let valid = true;
      for (let j = 0; j < bars; j++) {
        const c = candles[startIdx + j];
        if (!c || typeof c.close !== "number") {
          valid = false;
          break;
        }
      }
      if (!valid) continue;
      for (let j = 0; j < bars; j++) {
        const price = candles[startIdx + j].close;
        const diff = (price - startClose) * (dollarsPerMove ?? 1);
        changes[j].push(diff);
      }
    }
    const percentile = (sorted, p) => {
      if (!sorted.length) return 0;
      const n = sorted.length;
      const rank = (n - 1) * p;
      const lower = Math.floor(rank);
      const upper = Math.ceil(rank);
      if (lower === upper) return sorted[lower];
      const weight = rank - lower;
      return sorted[lower] * (1 - weight) + sorted[upper] * weight;
    };
    const result = [];
    for (let idx = 0; idx < bars; idx++) {
      const arr = changes[idx];
      if (!arr.length) {
        result.push({ x: idx + 1, avg: 0, median: 0, p10: 0, p90: 0 });
        continue;
      }
      const sorted = arr.slice().sort((a, b) => a - b);
      const len = sorted.length;
      const sum = sorted.reduce((acc, v) => acc + v, 0);
      const avg = sum / len;
      const mid = Math.floor(len / 2);
      const median =
        len % 2 === 1 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
      const p10Val = percentile(sorted, 0.1);
      const p90Val = percentile(sorted, 0.9);
      result.push({ x: idx + 1, avg, median, p10: p10Val, p90: p90Val });
    }
    return result;
  }, [candles, chunkBars, dollarsPerMove]);
