    const avgWin = winsCount > 0 ? sumWin / winsCount : 0;
    const avgLoss = lossesCount > 0 ? -(sumLossAbs / lossesCount) : 0;
    const rr = avgLoss !== 0 ? avgWin / Math.abs(avgLoss) : 0;
    const meanReturn = returns.reduce((a, b) => a + b, 0) / returns.length;
