      if (!t.closestCluster) continue;
      if (String(t.closestCluster) !== key) continue;
      const ex =
        (t.exitIndex ?? null) !== null
          ? t.exitIndex
          : Number.isFinite(t.entryIndex)
          ? t.entryIndex
          : -1;
