    let endMs = null;
    if (candles && candles.length > 1) {
      startMs = parseTimestamp(candles[0]?.time);
      endMs = parseTimestamp(candles[candles.length - 1]?.time);
    }
    if (startMs == null || endMs == null) {
      const times = [];
      for (const t of closed) {
        const a = parseTimestamp(t.entryTime);
        const b = parseTimestamp(t.exitTime || t.entryTime);
        if (a != null) times.push(a);
        if (b != null) times.push(b);
      }
      if (times.length) {
        times.sort((a, b) => a - b);
        startMs = times[0];
        endMs = times[times.length - 1];
      }
    }
