                              const bg =
                                opt.k === "real"
                                  ? "linear-gradient(135deg, rgba(200,50,50,0.22), rgba(230,80,80,0.16))"
                                  : "linear-gradient(135deg, rgba(120,80,255,0.22), rgba(0,210,255,0.14))";
